import logo from './logo.svg';
import './App.css';
import Home from './components/Home/Home'
import Euphonic from './components/Events/Euphonic'
import Unplugged from './components/Events/Unplugged'
import Inaugrals from './components/Events/Inaugrals'
import Meltdown from './components/Events/Meltdown'
import {
  BrowserRouter as Router,
  Switch,
  Route,
} from "react-router-dom";

function App() {
  return (
    <div className="App">
      <Router>
        <Switch>
          <Route exact path="/" component={Home} />
          <Route path="/euphonic" component={Euphonic} />
          <Route path="/unplugged" component={Unplugged} />
          <Route path="/inaugrals" component={Inaugrals} />
          <Route path="/meltdown" component={Meltdown} />
        </Switch>
      </Router>
    </div>
  );
}
export default App;
